        val humanReadableMessage: String?,
    ) {
        val isSuccess: Boolean
            get() = humanReadableMessage == null

        companion object {
            fun fromErrorString(message: String?): ImportResult = ImportResult(message)

            fun fromSuccess(): ImportResult = ImportResult(null)
